class BankAccount:
    def __init__(self, owner):
        self.owner = owner
        self.balance = 0

    def deposit(self, amount):
        self.balance += amount

    def withdraw(self, amount):
        if amount <= self.balance:
            self.balance -= amount
        else:
            print('Insufficient funds!')

acc = BankAccount('Alice')
acc.deposit(100)
acc.withdraw(30)
print(f'Final balance for {acc.owner}: ${acc.balance}')
